SELECT game_id AS gameId, MAX(game_name_zh) AS gameNameZh, MAX(game_name_en) AS gameNameEn, MAX(game_name_ko) AS gameNameKo, MAX(game_name_pt) AS gameNamePt, MAX(game_name_vi) AS gameNameVi, MAX(game_name_tr) AS gameNameTr, MAX(game_name_tw) AS gameNameTw, MAX(game_name_ja) AS gameNameJa, MAX(game_name_hi) AS gameNameHi, MAX(game_name_th) AS gameNameTh, MAX(game_name_ru) AS gameNameRu, MAX(game_name_ar) AS gameNameAr, MAX(game_type_code) AS gameTypeCode, MAX(plate_code) AS plateCode, MAX(plate_name_zh) AS plateNameZh, MAX(plate_name_en) AS plateNameEn, MAX(plate_name_ko) AS plateNameKo, MAX(plate_name_pt) AS plateNamePt, MAX(plate_name_vi) AS plateNameVi, MAX(plate_name_tr) AS plateNameTr, MAX(plate_name_tw) AS plateNameTw, MAX(plate_name_ja) AS plateNameJa, MAX(plate_name_hi) AS plateNameHi, MAX(plate_name_th) AS plateNameTh, MAX(plate_name_ru) AS plateNameRu, MAX(plate_name_ar) AS plateNameAr, IFNULL(SUM(bet_amount), 0) AS bet_amount, IFNULL(SUM(win), 0) AS win, IFNULL(SUM(win_loss), 0) AS win_loss, IFNULL(SUM(code_amount), 0) AS code_amount, CASE WHEN IFNULL(SUM(bet_amount), 0) = 0 THEN 0 ELSE ROUND(IFNULL(SUM(win), 0) / IFNULL(SUM(bet_amount), 0), 4) END AS payoutRate FROM t_order_term
order_type IN (0,1)
AND user_id = #{userId}
AND create_time BETWEEN #{createTimes[0], javaType=string, jdbcType=VARCHAR} AND #{createTimes[1], javaType=string, jdbcType=VARCHAR}
GROUP BY game_id

SELECT MAX(dealer_code) AS dealerCode, MAX(dealer_name) AS dealerName, plate_code AS plateCode, MAX(plate_name_zh) AS plateNameZh, MAX(plate_name_en) AS plateNameEn, MAX(plate_name_ko) AS plateNameKo, MAX(plate_name_pt) AS plateNamePt, MAX(plate_name_vi) AS plateNameVi, MAX(plate_name_tr) AS plateNameTr, MAX(plate_name_tw) AS plateNameTw, MAX(plate_name_ja) AS plateNameJa, MAX(plate_name_hi) AS plateNameHi, MAX(plate_name_th) AS plateNameTh, MAX(plate_name_ru) AS plateNameRu, MAX(plate_name_ar) AS plateNameAr, IFNULL(SUM(bet_amount), 0) AS bet_amount, IFNULL(SUM(win), 0) AS win, IFNULL(SUM(win_loss), 0) AS win_loss, IFNULL(SUM(code_amount), 0) AS code_amount, CASE WHEN IFNULL(SUM(bet_amount), 0) = 0 THEN 0 ELSE ROUND(IFNULL(SUM(win), 0) / IFNULL(SUM(bet_amount), 0), 4) END AS payoutRate FROM t_order_term
order_type IN (0,1)
AND user_id = #{userId}
AND create_time BETWEEN #{createTimes[0], javaType=string, jdbcType=VARCHAR} AND #{createTimes[1], javaType=string, jdbcType=VARCHAR}
GROUP BY plate_code

SELECT a.game_type_code AS gameTypeCode, MAX(b.type_name_zh) AS gameTypeNameZh, MAX(b.type_name_en) AS gameTypeNameEn, MAX(b.type_name_ko) AS gameTypeNameKo, MAX(b.type_name_pt) AS gameTypeNamePt, MAX(b.type_name_vi) AS gameTypeNameVi, MAX(b.type_name_tr) AS gameTypeNameTr, MAX(b.type_name_tw) AS gameTypeNameTw, MAX(b.type_name_ja) AS gameTypeNameJa, MAX(b.type_name_hi) AS gameTypeNameHi, MAX(b.type_name_th) AS gameTypeNameTh, MAX(b.type_name_ru) AS gameTypeNameRu, MAX(b.type_name_ar) AS gameTypeNameAr, IFNULL(SUM(a.bet_amount), 0) AS bet_amount, IFNULL(SUM(a.win), 0) AS win, IFNULL(SUM(a.win_loss), 0) AS win_loss, IFNULL(SUM(a.code_amount), 0) AS code_amount, CASE WHEN IFNULL(SUM(a.bet_amount), 0) = 0 THEN 0 ELSE ROUND(IFNULL(SUM(a.win), 0) / IFNULL(SUM(a.bet_amount), 0), 4) END AS payoutRate FROM t_order_term a LEFT JOIN t_game_type b ON a.game_type_code = b.type_code
a.order_type IN (0,1)
AND a.user_id = #{userId}
AND a.create_time BETWEEN #{createTimes[0], javaType=string, jdbcType=VARCHAR} AND #{createTimes[1], javaType=string, jdbcType=VARCHAR}
GROUP BY a.game_type_code
